/// <summary>
/// When CapexApprovalFeature is enabled then the field CapexApprovalId is made
/// Mandatory and visible
/// </summary>
/// <returns>int</returns>
int active()
{
    int ret =  next active();

    this.object(fieldNum(LedgerJournalTrans, ETGCapexApprovalId)).visible(AssetParameters::find().ETGCapexApprovalIdFeature);
    this.object(fieldNum(LedgerJournalTrans, ETGCapexApprovalId)).mandatory(AssetParameters::find().ETGCapexApprovalIdFeature);
    return ret;
}
